        //Count probes with status "Success"
        int count = 0;

        Iterator<SpaceProbeDTO> itrCount = spaceProbeDTOS.iterator();

        while (itrCount.hasNext()){
            SpaceProbeDTO element = itrCount.next();
            if(element.getStatus().equals("Success")){
                count++;
            }
        }
        System.out.println("probes with status \"Success\":"+count);
        System.out.println();


        //Count probes
        int count1 = 0;

        Iterator<SpaceProbeDTO> itrCount1 = spaceProbeDTOS.iterator();

        while (itrCount1.hasNext()){
            SpaceProbeDTO element = itrCount1.next();
            if(element.getPropulsionType().equals("Solar Electric")){
                count1++;
            }
        }
        System.out.println("Count probes with propulsionType \"Solar Electric\":"+count1);
        System.out.println();

        //Count probes
        int count2 = 0;

        Iterator<SpaceProbeDTO> itrCount2 = spaceProbeDTOS.iterator();

        while (itrCount2.hasNext()){
            SpaceProbeDTO element = itrCount2.next();
            if(element.isActive()){
                count2++;
            }
        }
        System.out.println("How many probes are currently active:"+count2);
        System.out.println();

        //Count probes
        int count3 = 0;

        Iterator<SpaceProbeDTO> itrCount3 = spaceProbeDTOS.iterator();

        while (itrCount3.hasNext()){
            SpaceProbeDTO element = itrCount3.next();
            if(element.getFuelRemaining() < 50){
                count3++;
            }
        }
        System.out.println("How many probes have fuelRemaining less than 50:"+count3);
        System.out.println();

        //Count probes
        int count4 = 0;

        Iterator<SpaceProbeDTO> itrCount4 = spaceProbeDTOS.iterator();

        while (itrCount4.hasNext()){
            SpaceProbeDTO element = itrCount4.next();
            if(element.getMissionDurationDays() > 365){
                count4++;
            }
        }
        System.out.println("How many probes have missionDurationDays greater than 365:"+count4);
        System.out.println();















        //Remove probes with status "Failed"
        int failed = 0;
        Iterator<SpaceProbeDTO> iterator1 = spaceProbeDTOS.iterator();

        while (iterator1.hasNext()){
            SpaceProbeDTO element = iterator1.next();

            if(element.getStatus().equals("Failed")){
                iterator1.remove();
                failed++;
            }
        }
        System.out.println("probes with status \"Failed\":"+failed);
        System.out.println();


        //Check if any probe targets Jupiter
        boolean found = false;
        Iterator<SpaceProbeDTO> iterator2 = spaceProbeDTOS.iterator();

        while (iterator2.hasNext()){
            SpaceProbeDTO element = iterator2.next();

            if(element.getTargetCelestialBody().equals("Jupiter")){
                found = true;
                break;
            }
        }
        System.out.println("Check if any probe targets Jupiter:"+found);
        System.out.println();


        //Verify all probes have manufacturer
        boolean valid = true;

        Iterator<SpaceProbeDTO> iterator3 = spaceProbeDTOS.iterator();

        while (iterator3.hasNext()){
            SpaceProbeDTO element = iterator3.next();

            if(element.getManufacturer() == null){
                valid = false;
                break;
            }
        }
        System.out.println("Verify all probes have manufacturer:"+valid);
